6	export interface AuthState {
7	  user: UserRead | undefined;
8	  isLoading: boolean;
9	  isError: boolean;
10	}
11	
12	/** Read the current authenticated user from the `['me']` query. */
13	export function useAuth(): AuthState {
14	  const { data, isLoading, isError } = useQuery({
15	    queryKey: ["me"],
16	    queryFn: getMe,
17	    retry: false,
18	  });
19	  return { user: data, isLoading, isError };
