32	async function request<T>(path: string, init?: RequestInit): Promise<T> {
33	  const res = await fetch(path, { credentials: "include", ...init });
34	  if (!res.ok) {
35	    let detail = res.statusText;
36	    try {
37	      const body = (await res.json()) as { detail?: unknown };
38	      if (typeof body.detail === "string") detail = body.detail;
39	    } catch {
40	      // non-JSON error body: keep statusText
41	    }
42	    throw new ApiError(res.status, detail);
43	  }
44	  if (res.status === 204) return undefined as T;
45	  return (await res.json()) as T;
46	}
